package com.google.gson.stream;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "com.google.gson.stream.steps"
)
public class CucumberTest {
    // Cucumber test runner for Gson JsonReader Top-level Values feature
}

package com.google.gson.stream.steps;

import com.google.gson.stream.JsonReader;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.junit.Assert;

import java.io.IOException;
import java.io.StringReader;

public class StepDefs {
    private JsonReader jsonReader;
    private String input;

    @Given("a JsonReader initialized with {string}")
    public void a_JsonReader_initialized_with(String jsonString) {
        this.input = jsonString;
        this.jsonReader = new JsonReader(new StringReader(jsonString));
    }

    @When("skipValue is called")
    public void skipValue_is_called() throws IOException {
        jsonReader.skipValue();
    }

    @Then("the next token should be END_DOCUMENT")
    public void the_next_token_should_be_END_DOCUMENT() throws IOException {
        // After calling skipValue, the reader should be at the end of the document
        try {
            // Try to peek at the next token
            com.google.gson.stream.JsonToken nextToken = jsonReader.peek();
            Assert.assertEquals("Expected END_DOCUMENT token after skipValue, but got: " + nextToken,
                              com.google.gson.stream.JsonToken.END_DOCUMENT, nextToken);
        } finally {
            if (jsonReader != null) {
                jsonReader.close();
            }
        }
    }
}

